function StickyCTA() {
  const [show, setShow] = useState(false);
  useEffect(() => { const h = () => setShow(window.scrollY > 500); window.addEventListener("scroll", h, { passive: true }); return () => window.removeEventListener("scroll", h); }, []);
  return <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, zIndex: 90, padding: "14px 20px", background: `${C.bg}f2`, backdropFilter: "blur(18px)", borderTop: `1px solid ${C.rose}10`, display: "flex", justifyContent: "center", transform: show ? "translateY(0)" : "translateY(100%)", transition: "transform .5s cubic-bezier(.16,1,.3,1)" }}>
    <Btn primary full href={LINKS.shop} sx={{ maxWidth: 380 }}>✦ &nbsp;Treat Yourself, Goddess</Btn>
  </div>;
}

